  const MobileAccordion: React.FC<{
    title: string;
    children: React.ReactNode;
    isOpen: boolean;
    onToggle: () => void;
  }> = ({ title, children, isOpen, onToggle }) => (
    <li className="bg-[#050a14]/50 rounded-xl overflow-hidden border border-white/10 shadow-lg">
      <button onClick={onToggle} className="flex justify-between items-center w-full p-4 text-white font-semibold text-left text-lg hover:bg-white/5 transition-colors">
        <span>{title}</span>
        <svg className={`w-5 h-5 text-[#F6520C] transform transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
